Here's a modern MSTest approach for testing your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        string result = await fetcher.FetchAsync("https://example.com/data");

        // Assert
        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        var handler = new MockHttpMessageHandler("content", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(5));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // guard against hangs — test fails if it exceeds 5s
    public async Task FetchAsync_SlowResponse_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("slow content", HttpStatusCode.OK, delay: TimeSpan.FromMilliseconds(100));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com/slow");

        Assert.AreEqual("slow content", result);
    }

    // Reusable test double — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `.Result` or `.GetAwaiter()` needed |
| `[Timeout(ms)]` | Fails the test if it hangs; works correctly with async methods in MSTest v3+ |
| `Assert.ThrowsExceptionAsync<T>` | Proper async exception assertion (not `ThrowsException`) |
| `CancellationToken` forwarding | Verifies your code actually honors cancellation |
| Custom `HttpMessageHandler` | Avoids mocking `HttpClient` directly (which is not designed for mocking) |

**Tip:** In MSTest v3+, you can also accept `CancellationToken` directly in your test method signature — MSTest will inject one that respects `[Timeout]`:

```csharp
[TestMethod]
[Timeout(3000)]
public async Task FetchAsync_WithInjectedToken(CancellationToken testCancellationToken)
{
    // testCancellationToken is cancelled automatically if the test exceeds 3s
    var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
    using var client = new HttpClient(handler);
    var fetcher = new DataFetcher(client);

    string result = await fetcher.FetchAsync("https://example.com", testCancellationToken);

    Assert.AreEqual("data", result);
}
```

This injected token pattern ties the test's timeout directly to the cancellation token passed into your production code, catching real hangs cleanly.
